add_action( 'wp_abilities_api_categories_init', function() {
    wp_register_ability_category( 'demo', array( 'label' => 'Demo' ) );
} );
add_action( 'wp_abilities_api_init', function() {
    wp_register_ability( 'demo/get-movies', array(
        'label'               => 'Get Movies',
        'category'            => 'demo',
        'input_schema'        => array(
            'type'       => 'object',
            'properties' => array( 'genre' => array( 'type' => 'string' ) ),
        ),
        'output_schema'       => array( 'type' => 'array', 'items' => array( 'type' => 'string' ) ),
        'permission_callback' => fn() => is_user_logged_in() && current_user_can( 'read' ),
        'callback'            => function () {
            $salt   = wp_cache_get_last_changed( 'posts' );
            $group  = 'post-queries';
            $key    = 'movies:list';
            $cached = wp_cache_get_salted( $key, $group, $salt, $found );
            if ( $found ) {
                return $cached;
            }
            $q      = new WP_Query( array( 'post_type' => 'movie', 'post_status' => 'publish', 'fields' => 'titles', 'nopaging' => true ) );
            $titles = wp_list_pluck( $q->posts, 'post_title' );
            wp_cache_set_salted( $key, $titles, $group, $salt );
            return $titles;
        },
        'meta'                => array( 'show_in_rest' => true ),
    ) );
} );
add_action( 'save_post_movie', fn() => wp_cache_delete( 'movies:list', 'post-queries' ) );
add_action( 'trashed_post', fn( $pid ) => wp_cache_delete( 'movies:list', 'post-queries' ) );
